#!/usr/bin/env tsx
/**
 * Discover YouTube auto-generated Topic channels for a curated artist list.
 *
 * Topic channels follow the pattern: "{Artist} - Topic" with a description
 * starting "Auto-generated by YouTube." They aggregate the audio-only versions
 * of every track in YouTube's catalog for that artist — and are a second
 * revenue leg for the labels TIPS / Saregama beyond their owned channels.
 *
 * Usage:
 *   YOUTUBE_API_KEY=... npx tsx scripts/discover-topic-channels.ts
 *
 * Cost: 100 quota units per search.list call. Default seed = ~35 artists →
 * ~3500 quota units. One-off.
 *
 * Output: JSON to stdout. Pipe to a file, review, then bulk-insert into
 * dim_channel via Supabase MCP (manual step — see end of script for SQL).
 */

const YT_API = 'https://www.googleapis.com/youtube/v3';
const KEY = process.env.YOUTUBE_API_KEY;
if (!KEY) {
  console.error('YOUTUBE_API_KEY environment variable required.');
  process.exit(1);
}

type Label = 'TIPSMUSIC' | 'SAREGAMA' | 'shared';

interface ArtistSeed {
  name: string;
  primary: Label;
  /** Optional: per-label catalog share (defaults: TIPS=1.0, SARE=1.0, shared={TIPS:0.5, SARE:0.5}) */
  share?: Partial<Record<'TIPSMUSIC' | 'SAREGAMA', number>>;
  /** Why this artist matters — for IR rationale on the bulk insert. */
  note?: string;
}

// =============================================================================
// Curated seed list. Attribution reflects whose catalog is most prominent for
// the artist on the labels we track. Soft weights via `share` capture cases
// where catalog is split (e.g. legacy Bollywood vocalists span multiple labels).
//
// Refine this list before running by adding/removing artists. The script
// validates "{Artist} - Topic" matches exactly + "Auto-generated by YouTube"
// in description, so namesakes / fan channels won't pollute results.
// =============================================================================
