interface Candidate {
  artist: string;
  primary: Label;
  share: Partial<Record<'TIPSMUSIC' | 'SAREGAMA', number>>;
  note?: string;
  channelId: string;
  title: string;
  subscribers: number;
  views: number;
}

interface SearchItem {
  snippet: {
    title: string;
    description: string;
    channelId: string;
  };
}

interface ChannelStatsItem {
  id: string;
  snippet: { title: string };
  statistics: { subscriberCount?: string; viewCount?: string };
}

/**
 * Topic channels are squatted heavily on YouTube — for any popular artist you
 * get 10+ channels titled "{Artist} - Topic" with single-digit subscriber
 * counts plus the canonical one with millions of subs. Strategy:
 *
 *   1. search.list q="{Artist} - Topic" maxResults=25 (100 quota units)
 *   2. Filter to title ∈ { "{Artist} - Topic", "{Artist} Topic" } (case-insensitive)
 *   3. Batch the candidate IDs through channels.list (1 quota per 50 IDs)
 *   4. Pick the one with the highest subscriber count, requiring ≥ 10k subs
 *      to filter spam
 */
async function searchTopicCandidates(seed: ArtistSeed): Promise<string[]> {
  // YT search treats quoted strings containing punctuation (the dash in
  // "Atif Aslam - Topic") restrictively and silently drops valid results.
  // Use a relaxed query and rely on the title-match filter for precision.
  const q = `${seed.name} Topic`;
  const url =
    `${YT_API}/search?part=snippet&q=${encodeURIComponent(q)}` +
    `&type=channel&maxResults=25&key=${KEY}`;
  const res = await fetch(url);
  if (!res.ok) {
    console.error(`  ✗ ${seed.name}: search HTTP ${res.status}`);
    return [];
  }
  const data = (await res.json()) as { items?: SearchItem[] };
  const dashed = `${seed.name.toLowerCase()} - topic`;
  const spaced = `${seed.name.toLowerCase()} topic`;
  return (data.items ?? [])
    .filter((i) => {
      const t = (i.snippet.title ?? '').toLowerCase().trim();
      return t === dashed || t === spaced;
    })
    .map((i) => i.snippet.channelId);
}

async function fetchChannelStats(ids: string[]): Promise<ChannelStatsItem[]> {
  if (ids.length === 0) return [];
  const out: ChannelStatsItem[] = [];
  // channels.list takes up to 50 ids per call
  for (let i = 0; i < ids.length; i += 50) {
    const batch = ids.slice(i, i + 50);
    const url =
      `${YT_API}/channels?part=snippet,statistics&id=${batch.join(',')}` +
      `&key=${KEY}`;
    const res = await fetch(url);
    if (!res.ok) {
      console.error(`  ✗ channels.list HTTP ${res.status}`);
      continue;
    }
    const data = (await res.json()) as { items?: ChannelStatsItem[] };
    out.push(...(data.items ?? []));
  }
  return out;
}

async function findTopicChannel(seed: ArtistSeed): Promise<Candidate | null> {
  const candidateIds = await searchTopicCandidates(seed);
  if (candidateIds.length === 0) return null;
  const stats = await fetchChannelStats(candidateIds);
  const ranked = stats
    .map((s) => ({
      id: s.id,
      title: s.snippet.title,
      subs: Number(s.statistics.subscriberCount ?? 0),
      views: Number(s.statistics.viewCount ?? 0),
    }))
    .filter((s) => s.subs >= 10_000) // filter spam Topic channels
    .sort((a, b) => b.subs - a.subs);
  if (ranked.length === 0) return null;
  const top = ranked[0];
  return {
    artist: seed.name,
    primary: seed.primary,
    share: seed.share ?? {},
    note: seed.note,
    channelId: top.id,
    title: top.title,
    subscribers: top.subs,
    views: top.views,
  };
}

async function main() {
  console.error(`Searching for ${ARTISTS.length} Topic channels...`);
  console.error(`Estimated quota cost: ${ARTISTS.length * 100} units.\n`);

  const found: Candidate[] = [];
  const missing: string[] = [];

  for (const seed of ARTISTS) {
    const result = await findTopicChannel(seed);
    if (result) {
      console.error(
        `  ✓ ${seed.name.padEnd(28)} → ${result.channelId} (subs=${result.subscribers.toLocaleString()}, views=${result.views.toLocaleString()})`,
      );
      found.push(result);
    } else {
      console.error(`  ✗ ${seed.name.padEnd(28)} → not found`);
      missing.push(seed.name);
    }
    await new Promise((r) => setTimeout(r, 150));
  }

  console.error(`\nFound ${found.length}/${ARTISTS.length}. Missing: ${missing.join(', ') || 'none'}\n`);

  // --- Emit JSON to stdout for piping/review --------------------------------
  console.log(JSON.stringify(found, null, 2));

  // --- Hint at the SQL the user will run after review ----------------------
  console.error('\n--- Next steps ---');
  console.error('1. Review the JSON above; remove any rows you do not want to track.');
  console.error('2. Apply migration 0009 via Supabase MCP if not already applied.');
  console.error('3. Insert into dim_channel + dim_artist_label using the JSON.');
  console.error('   Example SQL pattern:');
  console.error('     INSERT INTO dim_channel (channel_id, channel_name, channel_type, artist_name, ingest_videos)');
  console.error("     VALUES ('UC...', 'Arijit Singh - Topic', 'topic', 'Arijit Singh', false);");
  console.error("     INSERT INTO dim_artist_label (artist_name, company, catalog_share)");
  console.error("     VALUES ('Arijit Singh', 'TIPSMUSIC', 0.3),");
  console.error("            ('Arijit Singh', 'SAREGAMA', 0.3);");
}

main().catch((e) => {
  console.error(e);
  process.exit(1);
});
